mapper.select:
SELECT ICMP_ID, DEVICE_ID, RESPONSE_TIME, RESPONSE_MIN_TIME,
       RESPONSE_MAX_TIME, PACKET_LOSS, COLLECT_TIME
FROM p_icmp_t
WHERE DEVICE_ID = #{deviceId}
  AND COLLECT_TIME >= #{startDate}
  AND COLLECT_TIME <= #{endDate}
ORDER BY COLLECT_TIME

SELECT ICMP_ID, DEVICE_ID, RESPONSE_TIME, RESPONSE_MIN_TIME,
       RESPONSE_MAX_TIME, PACKET_LOSS, COLLECT_TIME
FROM p_icmp_t
WHERE DEVICE_ID IN

    #{id}

  AND COLLECT_TIME >= #{startDate}
  AND COLLECT_TIME <= #{endDate}
ORDER BY DEVICE_ID, COLLECT_TIME

SELECT DEVICE_ID, FROM_UNIXTIME(FLOOR(UNIX_TIMESTAMP(COLLECT_TIME)/#{intervalSec})*#{intervalSec}) AS COLLECT_TIME, ROUND(AVG(RESPONSE_TIME), 2) AS RESPONSE_TIME, ROUND(MIN(RESPONSE_MIN_TIME), 2) AS RESPONSE_MIN_TIME, ROUND(MAX(RESPONSE_MAX_TIME), 2) AS RESPONSE_MAX_TIME, ROUND(AVG(PACKET_LOSS), 2) AS PACKET_LOSS FROM p_icmp_t WHERE DEVICE_ID IN
#{id}
AND COLLECT_TIME >= #{startDate} AND COLLECT_TIME <= #{endDate} GROUP BY DEVICE_ID, FLOOR(UNIX_TIMESTAMP(COLLECT_TIME)/#{intervalSec}) ORDER BY DEVICE_ID, COLLECT_TIME
